import{_ as l,o as i,c as a,ae as o}from"./chunks/framework.jfJLTIcL.js";const b=JSON.parse('{"title":"公开发布仓","description":"","frontmatter":{},"headers":[],"relativePath":"zh-CN/public-distribution.md","filePath":"zh-CN/public-distribution.md","lastUpdated":null}'),c={name:"zh-CN/public-distribution.md"};function d(t,e,s,r,n,u){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="公开发布仓" tabindex="-1">公开发布仓 <a class="header-anchor" href="#公开发布仓" aria-label="Permalink to &quot;公开发布仓&quot;">​</a></h1><p>这份说明解释的是：VILab 的源码继续保留在私有仓库，但对外发布统一收口到一个公开仓库。</p><h2 id="公开仓库负责什么" tabindex="-1">公开仓库负责什么 <a class="header-anchor" href="#公开仓库负责什么" aria-label="Permalink to &quot;公开仓库负责什么&quot;">​</a></h2><ul><li>GitHub Releases：安装包、校验文件、签名文件、<code>latest.json</code></li><li>GitHub Pages：官网静态页</li><li>版本更新日志：由 <code>.github/releases/*.md</code> 自动生成</li><li>公共文档：固定挂在 <code>/docs/</code></li></ul><p>也就是说，开发过程继续在私有仓里，公开用户只接触公开站点和公开 release。</p><h2 id="推荐的公开仓结构" tabindex="-1">推荐的公开仓结构 <a class="header-anchor" href="#推荐的公开仓结构" aria-label="Permalink to &quot;推荐的公开仓结构&quot;">​</a></h2><ul><li>仓库名：<code>VILab-public</code></li><li>默认分支：<code>main</code></li><li>GitHub Pages：从 <code>main</code> 分支根目录发布</li><li>自定义域名：<code>app.&lt;你的域名&gt;</code></li></ul><h2 id="私有仓里必须配置的-secrets" tabindex="-1">私有仓里必须配置的 secrets <a class="header-anchor" href="#私有仓里必须配置的-secrets" aria-label="Permalink to &quot;私有仓里必须配置的 secrets&quot;">​</a></h2><ul><li><code>PUBLIC_RELEASE_REPO</code>：公开仓 slug，例如 <code>ERRORIGHT-AI/VILab-public</code></li><li><code>PUBLIC_RELEASE_PAT</code>：对公开仓有写权限的 token</li><li><code>PUBLIC_SITE_DOMAIN</code>：公开站点域名，例如 <code>app.example.com</code></li></ul><h2 id="现在这些-workflow-会做什么" tabindex="-1">现在这些 workflow 会做什么 <a class="header-anchor" href="#现在这些-workflow-会做什么" aria-label="Permalink to &quot;现在这些 workflow 会做什么&quot;">​</a></h2><ul><li><code>Sync Public Site</code><ul><li>构建 docs</li><li>生成官网首页、下载页、changelog 页面</li><li>把静态产物同步到公开仓</li></ul></li><li><code>Windows Release</code><ul><li>构建 Windows 安装包</li><li>生成 <code>latest.json</code></li><li>把 release assets 和版本说明上传到公开仓</li></ul></li><li><code>macOS Release</code><ul><li>构建并校验 macOS dmg</li><li>把 release assets 和版本说明上传到公开仓</li></ul></li></ul><h2 id="第一次接通时的检查清单" tabindex="-1">第一次接通时的检查清单 <a class="header-anchor" href="#第一次接通时的检查清单" aria-label="Permalink to &quot;第一次接通时的检查清单&quot;">​</a></h2><ol><li>新建公开仓库。</li><li>在 <code>main</code> 分支放一个初始提交。</li><li>在公开仓设置里把 GitHub Pages 指向 <code>main</code> 分支根目录。</li><li>在 Pages 设置里绑定你的自定义域名。</li><li>在 DNS 提供商处把这个子域名指向 GitHub Pages。</li><li>在私有源码仓里配置上面那三个 secrets。</li><li>手动运行一次 <code>Sync Public Site</code>，把公开站点内容先推上去。</li><li>再打一版 tag，检查 release assets 是否真的发布到公开仓。</li></ol><h2 id="本地可用命令" tabindex="-1">本地可用命令 <a class="header-anchor" href="#本地可用命令" aria-label="Permalink to &quot;本地可用命令&quot;">​</a></h2><ul><li>构建公开站点产物：<code>npm run public:site:build</code></li><li>把站点同步到公开仓：<code>npm run public:repo:sync</code></li><li>发布 Windows 版本：<code>npm run release:windows</code></li><li>发布 macOS 版本：<code>npm run release:mac</code></li></ul><h2 id="额外说明" tabindex="-1">额外说明 <a class="header-anchor" href="#额外说明" aria-label="Permalink to &quot;额外说明&quot;">​</a></h2><ul><li>桌面应用发布构建时，最好设置 <code>VITE_PUBLIC_SITE_URL</code>，这样应用里的文档入口会直接打开公开站点的 <code>/docs/</code>。</li><li>Tauri updater 现在已经指向公开发布仓。</li><li>现有 <code>.github/releases/*.md</code> 仍然是版本说明的单一来源，不需要改写你现在的 release notes 习惯。</li></ul>',17)])])}const p=l(c,[["render",d]]);export{b as __pageData,p as default};
